base32_string = '0123456789bcdefghjkmnpqrstuvwxyz'

def encode(double lat, double lng, int precision = 12):
	cdef list geohash = []
	cdef list bits = [16, 8, 4, 2, 1]

	cdef double max_lat = 90, min_lat = -90
	cdef double max_lng = 180, min_lng = -180
	cdef int even = 1
	cdef int bit, hash_pos, len_counter = 0
	cdef double mid

	while len_counter < precision:
		hash_pos = 0
		for bit in range(5):
			if even:
				mid = (max_lng + min_lng) / 2
				if lng > mid:
					hash_pos |= bits[bit]
					min_lng = mid
				else:
					max_lng = mid
			else:
				mid = (max_lat + min_lat) / 2
				if lat > mid:
					hash_pos |= bits[bit]
					min_lat = mid
				else:
					max_lat = mid
			even = 0 if even == 1 else 1

		geohash.append(base32_string[hash_pos])
		len_counter += 1

	return ''.join(geohash)

def decode(hash):
	cdef double max_lat = 90, min_lat = -90
	cdef double max_lng = 180, min_lng = -180
	cdef int i, even = 1, hash_pos, bit
	cdef double mid, lat, lng

	for i in range(len(hash)):
		hash_pos = base32_string.index(hash[i])
		for bit in range(4, -1, -1):
			if even == 1:
				mid = (max_lng + min_lng) / 2
				if ((hash_pos >> bit) & 1) == 1:
					min_lng = mid
				else:
					max_lng = mid
			else:
				mid = (max_lat + min_lat) / 2
				if ((hash_pos >> bit) & 1) == 1:
					min_lat = mid
				else:
					max_lat = mid
			even = 0 if even == 1 else 1

	lat = (min_lat + max_lat) / 2
	lng = (min_lng + max_lng) / 2

	return {
		'lat': lat,
		'lng': lng,
		'error': {
			'lat': max_lat - lat,
			'lng': max_lng - lng
		}
	}

from csv import reader as rdr
from libc.math cimport pow, sqrt


def load_dataset(path):
    rows = [r for r in rdr(open(path,'rb'))]

    dataset, targets = (
        [[float(x) for x in row[0:-1]] for row in rows][:-1],
        [row[-1:] for row in rows][:-1]
    )

    def compress_dataset(dataset, targets):
        cdef int i
        model = {}
        counts = {}

        for t, d in zip(targets, dataset):
            if t[0] not in model.keys():
                model[t[0]] = d
                counts[t[0]] = 1
            else:
                for i in xrange(len(d)):
                    model[t[0]][i] += d[i]
                counts[t[0]] += 1

        _model = {}

        for label in model.keys():
            data = model[label]
            for i in xrange(len(data)):
                data[i] = data[i] / float(counts[label])
            _model[label] = data

        targets = []
        dataset = []

        for t, d in _model.iteritems():
            targets.append([t])
            dataset.append(d)

        return dataset, targets

    return compress_dataset(dataset, targets)


cdef magnitude(list a, list b):
    cdef float x, y, distance

    distance = 0.0

    for x, y in zip(a,b):
        distance += pow(x-y, 2)

    distance = sqrt(distance)

    return distance


def classify(vector, dataset, outputs):
    if not (vector and dataset and outputs):
        raise ValueError("input data must not be empty")

    if not (len(vector) == len(dataset[0]) and 
            len(dataset) == len(outputs)):
        raise TypeError("data shape must be consistent")

    cdef int i
    indexes = [i for i in xrange(len(dataset))]
    distances = [magnitude(vector, x) for x in dataset]
    i = distances.index(min(distances))

    return outputs[i]
